     1→import type { ReactNode } from 'react';
     2→import { getAllPosts, getAllFlows, getFeaturedSeries, getSeriesData, getFeaturedPosts, getFeaturedBooks, getRecentFlows } from '@/lib/markdown';
     3→import { siteConfig } from '../../site.config';
     4→import Hero from '@/components/Hero';
     5→import CuratedSeriesSection, { SeriesItem } from '@/components/CuratedSeriesSection';
     6→import FeaturedStoriesSection, { FeaturedPost } from '@/components/FeaturedStoriesSection';
     7→import SelectedBooksSection, { BookItem } from '@/components/SelectedBooksSection';
     8→import LatestWritingSection from '@/components/LatestWritingSection';
     9→import RecentNotesSection, { RecentNoteItem } from '@/components/RecentNotesSection';
    10→import { Metadata } from 'next';
    11→import { resolveLocale } from '@/lib/i18n';
    12→
    13→export const metadata: Metadata = {
    14→  title: resolveLocale(siteConfig.title),
    15→  description: resolveLocale(siteConfig.description),
    16→  openGraph: {
    17→    title: resolveLocale(siteConfig.title),
    18→    description: resolveLocale(siteConfig.description),
    19→    siteName: resolveLocale(siteConfig.title),
    20→    url: siteConfig.baseUrl,
    21→    type: 'website',
    22→    images: [{ url: siteConfig.ogImage, width: 1200, height: 630 }],
    23→  },
    24→  twitter: {
    25→    card: 'summary',
    26→    title: resolveLocale(siteConfig.title),
    27→    description: resolveLocale(siteConfig.description),
    28→  },
    29→};
    30→
    31→type HomepageSection = {
    32→  id: string;
    33→  enabled?: boolean;
    34→  weight: number;
    35→  maxItems?: number;
    36→  scrollThreshold?: number;
    37→};
    38→
    39→export default function Home() {
    40→  const features = siteConfig.features;
    41→
    42→  // Resolve ordered, enabled homepage sections from config
    43→  const sections = ([...(siteConfig.homepage?.sections as HomepageSection[] ?? [])])
    44→    .filter(s => s.enabled !== false)
    45→    .sort((a, b) => a.weight - b.weight);
    46→
    47→  const has = (id: string) => sections.some(s => s.id === id);
    48→
    49→  // Derive per-section maxItems upfront for data loading
    50→  const recentFlowsMax = sections.find(s => s.id === 'recent-flows')?.maxItems ?? siteConfig.flows?.recentCount ?? 5;
    51→  const latestPostsMax = sections.find(s => s.id === 'latest-posts')?.maxItems ?? siteConfig.pagination.posts;
    52→
    53→  // Load data only for sections that are both enabled on homepage and globally
    54→  const allSeries = has('featured-series') && features?.series?.enabled !== false ? getFeaturedSeries() : {};
    55→  const featuredBooks = has('featured-books') && features?.books?.enabled !== false ? getFeaturedBooks() : [];
    56→  const recentFlows = has('recent-flows') && features?.flow?.enabled !== false
    57→    ? getRecentFlows(recentFlowsMax)
    58→    : [];
    59→  const needsPosts = has('featured-posts') || has('latest-posts');
    60→  const allPosts = needsPosts && features?.posts?.enabled !== false ? getAllPosts() : [];
    61→  const featuredPosts = has('featured-posts') && features?.posts?.enabled !== false ? getFeaturedPosts() : [];
    62→
    63→  const posts = allPosts.slice(0, latestPostsMax);
    64→
    65→  // Prepare serializable data for client components
    66→  const seriesItems: SeriesItem[] = has('featured-series') && features?.series?.enabled !== false
    67→    ? Object.keys(allSeries).map(name => {
    68→        const seriesPosts = allSeries[name];
    69→        const slug = name; // name is already the series directory slug
    70→        const seriesData = getSeriesData(slug);
    71→        return {
    72→          name,
    73→          title: seriesData?.title || name,
    74→          excerpt: seriesData?.excerpt || "A growing collection of related thoughts.",
    75→          coverImage: seriesData?.coverImage,
    76→          url: `/series/${slug}`,
    77→          postCount: seriesPosts.length,
    78→          topPosts: seriesPosts.slice(0, 3).map(p => ({ slug: p.slug, title: p.title })),
    79→        };
    80→      })
    81→    : [];
    82→
    83→  const bookItems: BookItem[] = has('featured-books') && features?.books?.enabled !== false
    84→    ? featuredBooks.map(b => ({
    85→        slug: b.slug,
    86→        title: b.title,
    87→        excerpt: b.excerpt,
    88→        coverImage: b.coverImage,
    89→        authors: b.authors,
    90→        chapterCount: b.chapters.length,
    91→        firstChapter: b.chapters[0]?.id,
    92→      }))
    93→    : [];
    94→
    95→  const recentNoteItems: RecentNoteItem[] = has('recent-flows') && features?.flow?.enabled !== false
    96→    ? recentFlows.map(f => ({
    97→        slug: f.slug,
    98→        date: f.date,
    99→        excerpt: f.excerpt,
   100→      }))
   101→    : [];
   102→
   103→  const featuredItems: FeaturedPost[] = has('featured-posts') && features?.posts?.enabled !== false
   104→    ? featuredPosts.map(p => ({
   105→        slug: p.slug,
   106→        title: p.title,
   107→        subtitle: p.subtitle,
   108→        excerpt: p.excerpt,
   109→        date: p.date,
   110→        category: p.category,
   111→        readingTime: p.readingTime,
   112→        coverImage: p.coverImage,
   113→        series: p.series,
   114→        pinned: p.pinned,
   115→      }))
   116→    : [];
   117→
   118→  // Stats for hero navigation chips
   119→  const heroPostCount = allPosts.length;
   120→  const heroSeriesCount = Object.keys(allSeries).length;
   121→  const heroBookCount = featuredBooks.length;
   122→  const heroFlowCount = has('hero') && features?.flow?.enabled !== false ? getAllFlows().length : 0;
   123→
   124→  const renderSection = (section: HomepageSection) => {
   125→    switch (section.id) {
   126→      case 'featured-series':
   127→        if (features?.series?.enabled === false) return null;
   128→        return (
   129→          <CuratedSeriesSection
   130→            key="featured-series"
   131→            allSeries={seriesItems}
   132→            maxItems={section.maxItems ?? 6}
   133→            scrollThreshold={section.scrollThreshold ?? 2}
   134→          />
   135→        );
   136→      case 'featured-books':
   137→        if (features?.books?.enabled === false) return null;
   138→        return (
   139→          <SelectedBooksSection
   140→            key="featured-books"
   141→            books={bookItems}
   142→            maxItems={section.maxItems ?? 4}
   143→          />
   144→        );
   145→      case 'featured-posts':
   146→        if (features?.posts?.enabled === false) return null;
   147→        return (
   148→          <FeaturedStoriesSection
   149→            key="featured-posts"
   150→            allFeatured={featuredItems}
   151→            maxItems={section.maxItems ?? 4}
   152→          />
   153→        );
   154→      case 'latest-posts':
   155→        if (features?.posts?.enabled === false) return null;
   156→        return <LatestWritingSection key="latest-posts" posts={posts} totalCount={allPosts.length} />;
   157→      case 'recent-flows':
   158→        if (features?.flow?.enabled === false) return null;
   159→        return <RecentNotesSection key="recent-flows" notes={recentNoteItems} />;
   160→      default:
   161→        return null;
   162→    }
   163→  };
   164→
   165→  // Build content sections, pairing latest-posts + recent-flows into a two-column layout
   166→  const sectionsForContent = sections.filter(s => s.id !== 'hero');
   167→  const latestIdx = sectionsForContent.findIndex(s => s.id === 'latest-posts');
   168→  const flowsIdx = sectionsForContent.findIndex(s => s.id === 'recent-flows');
   169→  const pairLatestFlows = latestIdx >= 0 && flowsIdx >= 0;
   170→
   171→  // Show a divider after the two-column section when series follows it
   172→  const divideBeforeSeries = pairLatestFlows
   173→    && has('featured-series')
   174→    && features?.series?.enabled !== false
   175→    && seriesItems.length > 0;
   176→
   177→  const renderList: ReactNode[] = [];
   178→  const skippedIds = new Set<string>();
   179→
   180→  for (const section of sectionsForContent) {
   181→    if (skippedIds.has(section.id)) continue;
   182→
   183→    if (pairLatestFlows && (section.id === 'latest-posts' || section.id === 'recent-flows')) {
   184→      skippedIds.add(section.id === 'latest-posts' ? 'recent-flows' : 'latest-posts');
   185→      const showLatest = features?.posts?.enabled !== false;
   186→      const showFlows = features?.flow?.enabled !== false && recentNoteItems.length > 0;
   187→      if (showLatest || showFlows) {
   188→        renderList.push(
   189→          <div key="latest-flows-combined" className={`grid grid-cols-1 lg:grid-cols-12 gap-12 lg:gap-16 ${divideBeforeSeries ? 'mb-16' : 'mb-24'}`}>
   190→            {showLatest && (
   191→              <div className="lg:col-span-7">
   192→                <LatestWritingSection posts={posts} totalCount={allPosts.length} />
   193→              </div>
   194→            )}
   195→            {showFlows && (
   196→              <div className="lg:col-span-5">
   197→                <RecentNotesSection notes={recentNoteItems} />
   198→              </div>
   199→            )}
   200→          </div>
   201→        );
   202→        if (divideBeforeSeries) {
   203→          renderList.push(
   204→            <div key="series-divider" className="border-t border-muted/10 mb-16" />
   205→          );
   206→        }
   207→      }
   208→    } else {
   209→      renderList.push(renderSection(section));
   210→    }
   211→  }
   212→
   213→  return (
   214→    <div>
   215→      {has('hero') && (
   216→        <Hero
   217→          tagline={siteConfig.hero.tagline}
   218→          title={siteConfig.hero.title}
   219→          subtitle={siteConfig.hero.subtitle}
   220→          postCount={heroPostCount}
   221→          seriesCount={heroSeriesCount}
   222→          bookCount={heroBookCount}
   223→          flowCount={heroFlowCount}
   224→          featureNames={{
   225→            flow:   features?.flow?.name,
   226→            posts:  features?.posts?.name,
   227→            series: features?.series?.name,
   228→            books:  features?.books?.name,
   229→          }}
   230→        />
   231→      )}
   232→
   233→      <div className="layout-main pt-0 md:pt-0 [&>*:last-child]:mb-0">
   234→        {renderList}
   235→      </div>
   236→    </div>
   237→  );
   238→}
