     3→import { useState, useCallback, useEffect } from 'react';
     4→import Link from 'next/link';
     5→import CoverImage from './CoverImage';
     6→import { useLanguage } from './LanguageProvider';
     7→import { shuffle } from '@/lib/shuffle';
     8→import { getPostUrl } from '@/lib/urls';
     9→
    10→export interface FeaturedPost {
    11→  slug: string;
    12→  title: string;
    13→  subtitle?: string;
    14→  excerpt: string;
    15→  date: string;
    16→  category: string;
    17→  readingTime: string;
    18→  coverImage?: string;
    19→  series?: string;
    20→  pinned?: boolean;
    21→}
    22→
    23→interface FeaturedStoriesSectionProps {
    24→  allFeatured: FeaturedPost[];
    25→  maxItems: number;
    26→}
    27→
    28→function buildDisplayed(allFeatured: FeaturedPost[], maxItems: number, shuffledNonPinned: FeaturedPost[]): FeaturedPost[] {
    29→  const pinned = allFeatured.filter(p => p.pinned);
    30→  const nonPinned = allFeatured.filter(p => !p.pinned);
    31→
    32→  const hero = pinned[0] ?? nonPinned[0];
    33→  if (!hero) return [];
    34→
    35→  const maxSecondaries = maxItems - 1;
    36→  const fixedSecondaries = pinned.slice(1, maxSecondaries + 1); // cap to available secondary slots
    37→  const shuffleSlots = Math.max(0, maxSecondaries - fixedSecondaries.length);
    38→
    39→  // Non-pinned pool excludes the hero if the hero is non-pinned
    40→  const heroIsNonPinned = !hero.pinned;
    41→  const shufflePool = heroIsNonPinned ? nonPinned.filter(p => p.slug !== hero.slug) : nonPinned;
    42→  const shuffledSlice = shuffledNonPinned.filter(p => shufflePool.some(q => q.slug === p.slug)).slice(0, shuffleSlots);
    43→
    44→  return [hero, ...fixedSecondaries, ...shuffledSlice];
    45→}
    46→
    47→export default function FeaturedStoriesSection({ allFeatured, maxItems }: FeaturedStoriesSectionProps) {
    48→  const { t } = useLanguage();
    49→
    50→  const nonPinned = allFeatured.filter(p => !p.pinned);
    51→
    52→  const [shuffledNonPinned, setShuffledNonPinned] = useState<FeaturedPost[]>(() => nonPinned);
    53→
    54→  useEffect(() => {
    55→    setShuffledNonPinned(shuffle(nonPinned));
    56→  // eslint-disable-next-line react-hooks/exhaustive-deps
    57→  }, [allFeatured]);
    58→
    59→  const handleShuffle = useCallback(() => {
    60→    setShuffledNonPinned(shuffle(nonPinned));
    61→  // eslint-disable-next-line react-hooks/exhaustive-deps
    62→  }, [allFeatured]);
    63→
    64→  const displayed = buildDisplayed(allFeatured, maxItems, shuffledNonPinned);
    65→
    66→  if (displayed.length === 0) return null;
    67→
    68→  // Show shuffle button only when there are more non-pinned posts than available shuffle slots
    69→  const pinned = allFeatured.filter(p => p.pinned);
    70→  const fixedCount = 1 + Math.min(pinned.slice(1).length, maxItems - 1);
    71→  const shuffleSlots = Math.max(0, maxItems - fixedCount);
    72→  const canShuffle = nonPinned.length > shuffleSlots + (pinned.length === 0 ? 1 : 0);
    73→
    74→  const [hero, ...secondary] = displayed;
    75→
    76→  return (
    77→    <section id="featured-posts" className="mb-24">
    78→      <div className="flex items-center justify-between mb-8">
    79→        <h2 className="text-3xl font-serif font-bold text-heading">{t('featured_articles')}</h2>
    80→        {canShuffle && (
    81→          <button
    82→            onClick={handleShuffle}
    83→            className="text-sm text-muted hover:text-accent transition-colors focus:outline-none"
    84→            aria-label="Shuffle featured stories"
    85→            title="Show different stories"
    86→          >
    87→            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={1.5}>
    88→              <path strokeLinecap="round" strokeLinejoin="round" d="M16 3h5v5M4 20L21 3M21 16v5h-5M15 15l6 6M4 4l5 5" />
    89→            </svg>
    90→          </button>
    91→        )}
    92→      </div>
    93→
    94→      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 lg:gap-8">
    95→        {/* Hero card — full image with obi (belly band) text overlay */}
    96→        <div className={secondary.length > 0 ? 'lg:col-span-7' : 'lg:col-span-12'}>
    97→          <Link href={getPostUrl(hero)} className={`group block no-underline${secondary.length > 0 ? ' h-full' : ''}`}>
    98→            <div className={`relative overflow-hidden rounded-2xl bg-muted/10 ${secondary.length > 0 ? 'aspect-[16/9] lg:aspect-auto lg:h-full' : 'aspect-[16/9]'}`}>
    99→              <CoverImage
   100→                src={hero.coverImage}
   101→                title={hero.title}
   102→                slug={hero.slug}
   103→                className="h-full w-full object-cover transition-transform duration-700 group-hover:scale-105"
   104→              />
   105→              {/* Gradient overlay */}
   106→              <div className="absolute inset-0 bg-gradient-to-t from-black/65 via-black/20 to-transparent" />
   107→              {/* Obi text band */}
   108→              <div className="absolute bottom-0 left-0 right-0 p-6 md:p-8">
   109→                <div className="flex items-center gap-2 text-xs font-mono text-white/60 mb-3">
   110→                  <span className="text-accent uppercase tracking-wider">{hero.category}</span>
   111→                  <span>·</span>
   112→                  <span>{hero.readingTime}</span>
   113→                  <span>·</span>
   114→                  <span>{hero.date}</span>
   115→                </div>
   116→                <h3 className="text-2xl md:text-3xl font-serif font-bold text-white mb-3 leading-snug group-hover:text-accent/90 transition-colors line-clamp-2">
   117→                  {hero.title}
   118→                </h3>
   119→                {(hero.subtitle || hero.excerpt) && (
   120→                  <p className="text-white/65 text-sm leading-relaxed line-clamp-1">
   121→                    {hero.subtitle || hero.excerpt}
   122→                  </p>
   123→                )}
   124→              </div>
   125→            </div>
   126→          </Link>
   127→        </div>
   128→
   129→        {/* Secondary cards — box style with flush right image */}
   130→        {secondary.length > 0 && (
   131→          <div className="lg:col-span-5 flex flex-col gap-4">
   132→            {secondary.map(post => (
   133→              <Link
   134→                key={post.slug}
   135→                href={getPostUrl(post)}
   136→                className="group flex no-underline rounded-2xl border border-muted/20 bg-muted/5 overflow-hidden hover:border-accent/30 hover:bg-muted/10 hover:shadow-lg hover:shadow-accent/5 transition-all duration-300 h-32"
   137→              >
   138→                {/* Text content */}
   139→                <div className="flex-1 p-4 flex flex-col min-w-0">
   140→                  <div className="flex items-center gap-2 text-xs font-mono text-muted mb-2">
   141→                    <span className="text-accent uppercase tracking-wider truncate max-w-[5rem]">{post.category}</span>
   142→                    <span className="shrink-0">·</span>
